# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int currentHealth;
    public int maxHealth = 100;
    public int currency = 500;
    public int damage = 10;
    public int priceForDamageUpgrade = 50;
    public int priceForHealthPotion = 30;

    void Start()
    {
        currentHealth = maxHealth;
    }

    public void TakeDamage(int amount)
    {
        currentHealth -= amount;
        if (currentHealth < 0)
        {
            currentHealth = 0;
        }
    }

    public bool UpgradeDamage()
    {
        if (currency >= priceForDamageUpgrade)
        {
            currency -= priceForDamageUpgrade;
            damage++;
            return true;
        }
        return false;
    }

    public bool BuyHealthPotion()
    {
        if (currency >= priceForHealthPotion)
        {
            currency -= priceForHealthPotion;
            currentHealth += 20; // Restore 20 health points
            if (currentHealth > maxHealth)
            {
                currentHealth = maxHealth;
            }
            return true;
        }
        return false;
    }

    public void DisplayStats()
    {
        Debug.Log("Current Health: " + currentHealth);
        Debug.Log("Currency: " + currency);
        Debug.Log("Damage: " + damage);
    }
}